1	type Item = { type: string; cursed?: boolean };
2	type ScenarioInput = { steps: { items: Item[] }[] };
3	
4	const PROCESSING_FEE = 5;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
7	const COMPONENT_BASE = 25;
8	const COMPONENT_BLOCK_BASE = 60;
9	const COMPONENT_BLOCK_SIZE = 3;
10	const ITEM_BASE_PREMIUM: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	function policyBase(items: Item[]): number {
18	  const components: Record<string, number> = {};
19	  let base = 0;
20	  for (const item of items) {
21	    if (COMPONENT_TYPES.has(item.type)) {
22	      components[item.type] = (components[item.type] ?? 0) + 1;
23	    } else {
24	      base += ITEM_BASE_PREMIUM[item.type];
25	    }
26	  }
27	  for (const count of Object.values(components)) {
28	    base += count === COMPONENT_BLOCK_SIZE
29	      ? COMPONENT_BLOCK_BASE
30	      : count * COMPONENT_BASE;
31	  }
32	  return base;
33	}
34	
35	function curseSurcharge(items: Item[]): number {
36	  let total = 0;
37	  for (const item of items) {
38	    if (item.cursed) {
39	      total += ITEM_BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE;
40	    }
41	  }
42	  return total;
43	}
44	
45	export function runScenario(input: unknown): unknown {
46	  const { steps: [{ items }] } = input as ScenarioInput;
47	  const base = policyBase(items);
48	  // Apply first-insurance 10% via integer tenths to avoid float drift,
49	  // then add cursed-item surcharges, round up, and add the flat fee.
50	  const premium = Math.ceil((base * 11) / 10 + curseSurcharge(items)) + PROCESSING_FEE;
51	  return { results: [{ premium }] };
52	}
